html:
{# COST PROPOSAL — Standard Print Format (SolidWurth Corp.) #}
{# Phase 13: wkhtmltopdf-safe rewrite — table layout, Frappe footer-html, no flex/fixed/opacity #}
{# Accent color: #A52422 (SW red) | Target renderer: wkhtmltopdf (Qt WebKit) #}

{%- set logo_path = frappe.db.get_single_value("Website Settings", "banner_image") -%}
{%- set fonts = get_fonts() -%}
{%- set prepared_by_name = frappe.db.get_value("User", doc.prepared_by, "full_name") if doc.prepared_by else "" -%}
{%- set checked_by_name = frappe.db.get_value("User", doc.checked_by, "full_name") if doc.checked_by else "" -%}
{%- set approved_by_name = frappe.db.get_value("User", doc.approved_by, "full_name") if doc.approved_by else "" -%}
{%- set company_tin = frappe.db.get_value("Company", "SolidWurth Corp.", "tax_id") or "" -%}

<style>
  /* -----------------------------------------------------------------------
     Page Setup — A4 Portrait (D9, D10)
  ----------------------------------------------------------------------- */
  @page {
    size: A4 portrait;
    margin: 15mm 15mm 20mm 20mm;
  }

  /* -----------------------------------------------------------------------
     Global Reset & Print Color Fix
  ----------------------------------------------------------------------- */
  * {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
    -webkit-print-color-adjust: exact !important;
    print-color-adjust: exact !important;
  }

  body {
    font-family: 'Inter', 'Helvetica Neue', Arial, sans-serif;
    font-size: 9pt;
    color: #2D3142;
    line-height: 1.4;
  }

  h1, h2, h3 {
    font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif;
    font-weight: 700;
  }

  .amount-cell {
    font-family: 'Roboto Mono', 'Courier New', monospace;
    text-align: right;
  }

  /* -----------------------------------------------------------------------
     Font Embedding (base64, graceful degradation)
  ----------------------------------------------------------------------- */
  {% if fonts.montserrat_bold %}
  @font-face {
    font-family: 'Montserrat';
    font-weight: 700;
    font-style: normal;
    src: url('data:font/woff2;base64,{{ fonts.montserrat_bold }}') format('woff2');
  }
  {% endif %}
  {% if fonts.inter_regular %}
  @font-face {
    font-family: 'Inter';
    font-weight: 400;
    font-style: normal;
    src: url('data:font/woff2;base64,{{ fonts.inter_regular }}') format('woff2');
  }
  {% endif %}
  {% if fonts.roboto_mono %}
  @font-face {
    font-family: 'Roboto Mono';
    font-weight: 400;
    font-style: normal;
    src: url('data:font/woff2;base64,{{ fonts.roboto_mono }}') format('woff2');
  }
  {% endif %}

  /* -----------------------------------------------------------------------
     Table Defaults — wkhtmltopdf-safe (NO flexbox anywhere)
  ----------------------------------------------------------------------- */
  table {
    width: 100%;
    border-collapse: collapse;
  }

  thead {
    display: table-header-group;
  }

  tbody tr {
    page-break-inside: avoid;
  }

  .summary-table {
    table-layout: fixed;
  }

  .waterfall-table {
    page-break-inside: avoid;
  }

  /* -----------------------------------------------------------------------
     Cover Page Info Table
  ----------------------------------------------------------------------- */
  .info-label {
    padding: 4px 8px;
    font-weight: bold;
    color: #1B2E4A;
    width: 35%;
    white-space: nowrap;
    font-size: 10pt;
    border-bottom: 1px solid #e0e0e0;
    vertical-align: top;
  }

  .info-value {
    padding: 4px 8px;
    color: #2D3142;
    font-size: 10pt;
    border-bottom: 1px solid #e0e0e0;
    vertical-align: top;
  }

  /* -----------------------------------------------------------------------
     Section Headers (DLIA sections A/B/C)
  ----------------------------------------------------------------------- */
  .section-header {
    background-color: #2E5FA3;
    color: #ffffff;
    padding: 4px 10px;
    font-size: 8pt;
    font-weight: bold;
    margin-bottom: 2mm;
    margin-top: 4mm;
  }

</style>

{# =========================================================================
   FRAPPE FOOTER — extracted for --footer-html in wkhtmltopdf
   Hidden in browser print preview via @media screen rule above.
   <span class="page"> / <span class="topage"> = reliable page numbers
========================================================================= #}
<div id="footer-html" class="visible-pdf" style="display: none;">
  <div style="width: 100%; border-top: 1px solid #1B2E4A; padding: 2mm 0; font-size: 7pt; color: #555555;">
    <table style="width: 100%; border-collapse: collapse;">
      <tr>
        <td style="text-align: left; padding: 0 4mm; font-weight: bold;">
          SolidWurth Corp.{% if company_tin %} | TIN: {{ company_tin }}{% endif %}
        </td>
        <td style="text-align: center; padding: 0 4mm; font-style: italic; color: #A52422;">
          CONFIDENTIAL &mdash; FOR PROPOSAL PURPOSES ONLY
        </td>
        <td style="text-align: right; padding: 0 4mm;">
          Page <span class="page"></span> of <span class="topage"></span>
        </td>
      </tr>
    </table>
  </div>
</div>

{# =========================================================================
   MACRO: Inline Continuation Header
   Table-based (not position:fixed). Placed at top of each section after cover.
========================================================================= #}
{% macro cont_header() %}
<table style="width: 100%; background-color: #1B2E4A; border-bottom: 2px solid #A52422; margin-bottom: 6mm; border-collapse: collapse;">
  <tr>
    <td style="padding: 2mm 4mm; width: 25mm; vertical-align: middle;">
      {% if logo_path %}<img src="{{ logo_path }}" style="max-height: 8mm; width: auto;" alt="" />{% endif %}
    </td>
    <td style="padding: 2mm 4mm; text-align: center; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-weight: 700; font-size: 9pt; color: #ffffff; letter-spacing: 0.5px; vertical-align: middle;">
      COST PROPOSAL &mdash; {{ doc.name }}{% if doc.revision %} | Rev {{ doc.revision }}{% endif %}
    </td>
    <td style="padding: 2mm 4mm; text-align: right; width: 35mm; font-size: 7.5pt; color: #D0D7E0; white-space: nowrap; vertical-align: middle;">
      {{ doc.name }}
    </td>
  </tr>
</table>
{% endmacro %}

{# =========================================================================
   COVER PAGE (D3, D11, D12)
========================================================================= #}
<div style="page-break-after: always;">

  {# Navy band — centered via text-align (no flexbox) #}
  <div style="background-color: #1B2E4A; width: 100%; padding: 18mm 20mm 14mm 20mm; text-align: center;">
    {% if logo_path %}
      <img src="{{ logo_path }}" style="max-height: 50mm; max-width: 120mm; margin-bottom: 8mm;" alt="SolidWurth Corp." />
    {% else %}
      <div style="font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-size: 20pt; font-weight: 700; color: #ffffff; margin-bottom: 6mm;">SolidWurth Corp.</div>
    {% endif %}
    <div style="font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-weight: 700; font-size: 28pt; color: #ffffff; letter-spacing: 2px; text-transform: uppercase;">COST PROPOSAL</div>
    <div style="width: 80mm; height: 4px; background-color: #A52422; margin: 6mm auto 0 auto;"></div>
  </div>

  {# Project info table #}
  <div style="padding: 10mm 20mm;">
    <table style="width: 100%; border-collapse: collapse; margin-bottom: 6mm;">
      <tbody>
        <tr>
          <td class="info-label">Project:</td>
          <td class="info-value">{{ doc.estimate_title or doc.project or "&mdash;" }}</td>
        </tr>
        <tr>
          <td class="info-label">Client:</td>
          <td class="info-value">{{ doc.client or "&mdash;" }}</td>
        </tr>
        <tr>
          <td class="info-label">Location:</td>
          <td class="info-value">{{ doc.project or "&mdash;" }}</td>
        </tr>
        <tr>
          <td class="info-label">Estimate No.:</td>
          <td class="info-value">{{ doc.name }}</td>
        </tr>
        <tr>
          <td class="info-label">Date:</td>
          <td class="info-value">{{ frappe.utils.formatdate(doc.estimate_date, "dd MMM yyyy") if doc.estimate_date else "&mdash;" }}</td>
        </tr>
        <tr>
          <td class="info-label">Valid Until:</td>
          <td class="info-value">{{ frappe.utils.formatdate(doc.valid_until, "dd MMM yyyy") if doc.valid_until else "&mdash;" }}</td>
        </tr>
        {% if doc.description %}
        <tr>
          <td class="info-label">Scope Summary:</td>
          <td class="info-value">{{ doc.description }}</td>
        </tr>
        {% endif %}
      </tbody>
    </table>
  </div>

  {# Signature block — TABLE-based (3 equal columns), pinned near page bottom #}
  <div style="padding: 8mm 20mm 10mm 20mm; border-top: 2px solid #1B2E4A; margin-top: 15mm;">
    <table style="width: 100%; border-collapse: collapse;">
      <tr>
        <td style="width: 33.33%; text-align: center; padding: 0 4mm; vertical-align: top;">
          <div style="font-size: 7.5pt; font-weight: bold; color: #1B2E4A; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 10mm;">Prepared By</div>
          <div style="border-bottom: 1px solid #1B2E4A; margin: 0 4mm 2mm 4mm;">&nbsp;</div>
          <div style="font-size: 8.5pt; color: #2D3142; font-weight: bold; min-height: 12px;">{{ prepared_by_name or "&nbsp;" }}</div>
        </td>
        <td style="width: 33.33%; text-align: center; padding: 0 4mm; vertical-align: top;">
          <div style="font-size: 7.5pt; font-weight: bold; color: #1B2E4A; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 10mm;">Checked By</div>
          <div style="border-bottom: 1px solid #1B2E4A; margin: 0 4mm 2mm 4mm;">&nbsp;</div>
          <div style="font-size: 8.5pt; color: #2D3142; font-weight: bold; min-height: 12px;">{{ checked_by_name or "&nbsp;" }}</div>
        </td>
        <td style="width: 33.33%; text-align: center; padding: 0 4mm; vertical-align: top;">
          <div style="font-size: 7.5pt; font-weight: bold; color: #1B2E4A; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 10mm;">Approved By</div>
          <div style="border-bottom: 1px solid #1B2E4A; margin: 0 4mm 2mm 4mm;">&nbsp;</div>
          <div style="font-size: 8.5pt; color: #2D3142; font-weight: bold; min-height: 12px;">{{ approved_by_name or "&nbsp;" }}</div>
        </td>
      </tr>
    </table>
  </div>

</div>{# end cover page #}

{# =========================================================================
   SUMMARY PAGE (D5, D13, D14)
   - Grouped by scope_group (header rows) — no Scope Group column
   - 4 columns: Scope of Work | UOM | Qty | Direct Cost
   - Waterfall: full-width, 3-column (Component | % | Amount)
========================================================================= #}

{% set scopes = frappe.db.sql("""
    SELECT name, scope_name, scope_group, is_optional, direct_cost, quantity, uom
    FROM `tabEstimate Scope`
    WHERE estimate = %s
    ORDER BY scope_group ASC, COALESCE(display_order, 999) ASC, name ASC
""", doc.name, as_dict=True) %}

{% set base_scopes = scopes | selectattr("is_optional", "eq", 0) | list %}
{% set optional_scopes = scopes | selectattr("is_optional", "ne", 0) | list %}

<div style="page-break-after: always;">

  {{ cont_header() }}

  <div style="background-color: #1B2E4A; color: #ffffff; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-size: 13pt; font-weight: 700; padding: 8px 12px; letter-spacing: 1px; margin-bottom: 8mm;">
    SUMMARY OF COST ESTIMATE
  </div>

  {% if scopes %}
  <table class="summary-table" style="table-layout: fixed; width: 100%; border-collapse: collapse; font-size: 9pt;">
    <colgroup>
      <col style="width: 45%;">
      <col style="width: 12%;">
      <col style="width: 13%;">
      <col style="width: 30%;">
    </colgroup>
    <thead>
      <tr>
        <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: left;">Scope of Work</th>
        <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: left;">UOM</th>
        <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: right;">Qty</th>
        <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: right;">Direct Cost</th>
      </tr>
    </thead>
    <tbody>

      {# === BASE SCOPES — grouped by scope_group === #}
      {% set current_grp = namespace(value=None) %}
      {% set grp_idx = namespace(value=0) %}
      {% for scope in base_scopes %}
        {% if scope.scope_group != current_grp.value %}
          {% set current_grp.value = scope.scope_group %}
          {% set grp_idx.value = 0 %}
          <tr>
            <td colspan="4" style="background-color: #1B2E4A; color: #ffffff; font-weight: bold; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; padding: 5px 10px; font-size: 9pt; letter-spacing: 0.5px;">
              {{ scope.scope_group }}
            </td>
          </tr>
        {% endif %}
        {% set grp_idx.value = grp_idx.value + 1 %}
        <tr{% if grp_idx.value % 2 == 0 %} style="background-color: #F4F6F9;"{% endif %}>
          <td style="padding: 5px 8px 5px 16px; border-bottom: 1px solid #e8e8e8;">{{ scope.scope_name }}</td>
          <td style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ scope.uom if scope.uom and scope.uom != "None" else "&mdash;" }}</td>
          <td class="amount-cell" style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ num_format(scope.quantity) }}</td>
          <td class="amount-cell" style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ php_format(scope.direct_cost) }}</td>
        </tr>
      {% endfor %}

      {# Base scopes subtotal #}
      {% if base_scopes %}
      <tr>
        <td colspan="3" style="text-align: right; font-weight: bold; padding: 5px 8px; background-color: #dde4f0; border-top: 2px solid #2E5FA3; border-bottom: 2px solid #2E5FA3;">Base Scope Subtotal</td>
        <td class="amount-cell" style="font-weight: bold; padding: 5px 8px; background-color: #dde4f0; border-top: 2px solid #2E5FA3; border-bottom: 2px solid #2E5FA3;">{{ php_format(doc.base_direct_cost) }}</td>
      </tr>
      {% endif %}

      {# === OPTIONAL SCOPES — grouped by scope_group === #}
      {% if optional_scopes %}
      <tr>
        <td colspan="4" style="padding: 8px 8px 2px 8px; font-weight: bold; color: #2E5FA3; font-size: 8.5pt; font-style: italic;">
          Optional Scopes
        </td>
      </tr>
      {% set current_grp_opt = namespace(value=None) %}
      {% set grp_idx_opt = namespace(value=0) %}
      {% for scope in optional_scopes %}
        {% if scope.scope_group != current_grp_opt.value %}
          {% set current_grp_opt.value = scope.scope_group %}
          {% set grp_idx_opt.value = 0 %}
          <tr>
            <td colspan="4" style="background-color: #2E5FA3; color: #ffffff; font-weight: bold; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; padding: 4px 10px; font-size: 8.5pt; letter-spacing: 0.5px;">
              {{ scope.scope_group }}
            </td>
          </tr>
        {% endif %}
        {% set grp_idx_opt.value = grp_idx_opt.value + 1 %}
        <tr{% if grp_idx_opt.value % 2 == 0 %} style="background-color: #F4F6F9;"{% endif %}>
          <td style="padding: 5px 8px 5px 16px; border-bottom: 1px solid #e8e8e8;">{{ scope.scope_name }}</td>
          <td style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ scope.uom if scope.uom and scope.uom != "None" else "&mdash;" }}</td>
          <td class="amount-cell" style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ num_format(scope.quantity) }}</td>
          <td class="amount-cell" style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ php_format(scope.direct_cost) }}</td>
        </tr>
      {% endfor %}

      {# Optional scopes subtotal #}
      {% set optional_dc = namespace(total=0) %}
      {% for s in optional_scopes %}{% set optional_dc.total = optional_dc.total + (s.direct_cost | float) %}{% endfor %}
      <tr>
        <td colspan="3" style="text-align: right; font-weight: bold; padding: 5px 8px; background-color: #dde4f0; border-top: 2px solid #2E5FA3; border-bottom: 2px solid #2E5FA3;">Optional Scope Subtotal</td>
        <td class="amount-cell" style="font-weight: bold; padding: 5px 8px; background-color: #dde4f0; border-top: 2px solid #2E5FA3; border-bottom: 2px solid #2E5FA3;">{{ php_format(optional_dc.total) }}</td>
      </tr>
      {% endif %}

      {# Grand Total row #}
      <tr>
        <td colspan="3" style="padding: 6px 8px; text-align: right; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-weight: bold; background-color: #1B2E4A; color: #ffffff;">Grand Total Direct Cost (All Scopes)</td>
        <td class="amount-cell" style="padding: 6px 8px; font-weight: bold; background-color: #1B2E4A; color: #ffffff;">{{ php_format(doc.direct_cost) }}</td>
      </tr>
      {# Base Grand Total — only when BOTH base and optional exist #}
      {% if base_scopes and optional_scopes %}
      <tr>
        <td colspan="3" style="padding: 4px 8px; text-align: right; font-size: 8pt; background-color: #2E5FA3; color: #ffffff;">Base Scope Grand Total Direct Cost</td>
        <td class="amount-cell" style="padding: 4px 8px; font-size: 8pt; background-color: #2E5FA3; color: #ffffff;">{{ php_format(doc.base_direct_cost) }}</td>
      </tr>
      {% endif %}

    </tbody>
  </table>

  {# Waterfall — full-width, 3-column (Component | % | Amount) #}
  <div style="margin-top: 6mm;">
    {{ render_waterfall_block(doc.direct_cost | float, doc.ocm_percent | float, doc.profit_percent | float, doc.vat_inclusive, doc.vat_percent | float, "#A52422") }}
  </div>

  {% if optional_scopes %}
  <div style="margin-top: 4mm; font-size: 8pt; font-style: italic; color: #666666; text-align: right;">
    * Grand Total includes optional scopes ({{ optional_scopes | length }} scope{{ 's' if optional_scopes | length != 1 }}).
    Base-only Grand Total: {{ php_format(doc.base_grand_total) }}
  </div>
  {% endif %}

  {% else %}
  {# Empty estimate #}
  <div style="padding: 20mm 0; text-align: center; color: #888888; font-style: italic;">
    <p style="font-size: 11pt;">No scopes added</p>
    <p style="margin-top: 4mm; font-size: 9pt;">Grand Total: {{ php_format(0) }}</p>
  </div>
  {% endif %}

</div>{# end summary page #}

{# =========================================================================
   SCOPE DETAIL PAGES
   - Sections: A (Labor), B (Equipment & Plant), C (Materials)
   - Equipment SQL: LEFT JOIN tabItem for item_name
   - Waterfall: full-width, margin-top: 8mm
   - All dark backgrounds have explicit white text
========================================================================= #}

{% set scopes_detail = frappe.db.sql("""
    SELECT name, scope_name, scope_group, is_optional, dpwh_pay_item,
           uom, quantity, output_per_day, duration_days, display_order,
           direct_cost, total_labor_cost, total_equipment_cost, total_material_cost
    FROM `tabEstimate Scope`
    WHERE estimate = %s
    ORDER BY scope_group ASC, COALESCE(display_order, 999) ASC, name ASC
""", doc.name, as_dict=True) %}

{% set scope_count = scopes_detail | length %}
{% set current_group = namespace(value=None) %}
{% set scope_num = namespace(value=0) %}

{% if scope_count > 0 %}

{% if doc.cost_display_mode == "Summary (Private)" %}
{# -----------------------------------------------------------------------
   Summary (Private) mode
----------------------------------------------------------------------- #}
{% for scope in scopes_detail %}
  {% set scope_num.value = scope_num.value + 1 %}

  <div style="page-break-before: always;">

    {{ cont_header() }}

    {# Scope header — TABLE-based, all text white on navy #}
    <table style="width: 100%; background-color: #1B2E4A; color: #ffffff; margin-bottom: 4mm; border-collapse: collapse;">
      <tr>
        <td style="padding: 8px 10px; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-size: 9pt; color: #ffffff; vertical-align: top;">
          <strong>{{ scope.scope_name }}</strong>
          {% if scope.is_optional %}<span style="font-style: italic; color: #CCCCCC;"> (Optional)</span>{% endif %}
        </td>
        <td style="padding: 8px 10px; text-align: right; font-size: 8.5pt; color: #ffffff; vertical-align: top; white-space: nowrap;">
          {{ scope.uom if scope.uom and scope.uom != "None" else "" }} &times; {{ num_format(scope.quantity) }}
        </td>
      </tr>
      <tr>
        <td colspan="2" style="padding: 0 10px 6px 10px; font-size: 8pt; color: #D0D7E0;">
          {{ scope.scope_group }}
          {% if scope.dpwh_pay_item %} | Pay Item: {{ scope.dpwh_pay_item }}{% endif %}
        </td>
      </tr>
    </table>

    {# Unit cost + total table #}
    <div style="margin-bottom: 4mm;">
      <table style="width: 100%; border-collapse: collapse; font-size: 9pt;">
        <thead>
          <tr>
            <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: left;">Description</th>
            <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: right;">Unit Cost</th>
            <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: right;">Total Direct Cost</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ scope.scope_name }}</td>
            {% set unit_cost = (scope.direct_cost | float) / (scope.quantity | float) if (scope.quantity | float) > 0 else 0 %}
            <td class="amount-cell" style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ php_format(unit_cost) }}</td>
            <td class="amount-cell" style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ php_format(scope.direct_cost) }}</td>
          </tr>
        </tbody>
      </table>
    </div>

    {# Waterfall — full-width #}
    <div style="margin-top: 8mm; page-break-inside: avoid;">
      {{ render_waterfall_block(scope.direct_cost | float, doc.ocm_percent | float, doc.profit_percent | float, doc.vat_inclusive, doc.vat_percent | float, "#A52422") }}
    </div>

  </div>
{% endfor %}

{% else %}
{# -----------------------------------------------------------------------
   Detailed (DPWH) mode — DLIA sections A/B/C per scope
----------------------------------------------------------------------- #}
{% for scope in scopes_detail %}
  {% set scope_num.value = scope_num.value + 1 %}

  <div style="page-break-before: always;">

    {{ cont_header() }}

    {# Scope group header on group change #}
    {% if scope.scope_group != current_group.value %}
      {% set current_group.value = scope.scope_group %}
      <div style="background-color: #1B2E4A; color: #ffffff; font-weight: bold; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; padding: 6px 10px; letter-spacing: 1px; font-size: 9.5pt; margin-bottom: 4mm;">
        {{ scope.scope_group | upper }}
      </div>
    {% endif %}

    {# Scope header bar — TABLE-based, explicit white text on navy #}
    <table style="width: 100%; background-color: #1B2E4A; color: #ffffff; margin-bottom: 4mm; border-collapse: collapse;">
      <tr>
        <td style="padding: 8px 10px; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-size: 9pt; color: #ffffff; vertical-align: top;">
          <strong>SCOPE {{ scope_num.value }} of {{ scope_count }}</strong>: {{ scope.scope_name }}
