  </div>

  {% if scopes %}
  <table class="summary-table" style="table-layout: fixed; width: 100%; border-collapse: collapse; font-size: 9pt;">
    <colgroup>
      <col style="width: 45%;">
      <col style="width: 12%;">
      <col style="width: 13%;">
      <col style="width: 30%;">
    </colgroup>
    <thead>
