    FROM `tabEstimate Scope`
    WHERE estimate = %s
    ORDER BY scope_group ASC, COALESCE(display_order, 999) ASC, name ASC
""", doc.name, as_dict=True) %}

{% set scope_count = scopes_detail | length %}
{% set current_group = namespace(value=None) %}
{% set scope_num = namespace(value=0) %}

{% if scope_count > 0 %}

{% if doc.cost_display_mode == "Summary (Private)" %}
{# Summary (Private) mode — BP variant #}
{% for scope in scopes_detail %}
  {% set scope_num.value = scope_num.value + 1 %}

  {# Compute BP direct cost for this scope #}
  {% set scope_mat_rows = frappe.db.sql("SELECT amount FROM `tabEstimate Scope Material` WHERE parent = %s", scope.name, as_dict=True) %}
  {% set scope_bp_mat = namespace(value=0) %}
  {% for row in scope_mat_rows %}{% set scope_bp_mat.value = scope_bp_mat.value + (row.amount | float) * bp_rate %}{% endfor %}
  {% set scope_bp_dc = (scope.total_labor_cost | float) + (scope.total_equipment_cost | float) + scope_bp_mat.value %}

  <div style="page-break-before: always;">

    {{ cont_header() }}

    <table style="width: 100%; background-color: #1B2E4A; color: #ffffff; margin-bottom: 4mm; border-collapse: collapse;">
      <tr>
        <td style="padding: 8px 10px; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-size: 9pt; color: #ffffff; vertical-align: top;">
          <strong>{{ scope.scope_name }}</strong>
          {% if scope.is_optional %}<span style="font-style: italic; color: #CCCCCC;"> (Optional)</span>{% endif %}
        </td>
        <td style="padding: 8px 10px; text-align: right; font-size: 8.5pt; color: #ffffff; vertical-align: top; white-space: nowrap;">
          {{ scope.uom if scope.uom and scope.uom != "None" else "" }} &times; {{ num_format(scope.quantity) }}
        </td>
      </tr>
      <tr>
        <td colspan="2" style="padding: 0 10px 6px 10px; font-size: 8pt; color: #D0D7E0;">
          {{ scope.scope_group }}
          {% if scope.dpwh_pay_item %} | Pay Item: {{ scope.dpwh_pay_item }}{% endif %}
        </td>
      </tr>
    </table>

    <div style="margin-bottom: 4mm;">
      <table style="width: 100%; border-collapse: collapse; font-size: 9pt;">
        <thead>
          <tr>
            <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: left;">Description</th>
            <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: right;">BP Unit Cost</th>
            <th style="background-color: #3B5998; color: #ffffff; padding: 6px 8px; text-align: right;">BP Direct Cost</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ scope.scope_name }}</td>
            {% set bp_unit_cost = scope_bp_dc / (scope.quantity | float) if (scope.quantity | float) > 0 else 0 %}
            <td class="amount-cell" style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ php_format(bp_unit_cost) }}</td>
            <td class="amount-cell" style="padding: 5px 8px; border-bottom: 1px solid #e8e8e8;">{{ php_format(scope_bp_dc) }}</td>
          </tr>
        </tbody>
      </table>
    </div>

    <div style="margin-top: 8mm; page-break-inside: avoid;">
      {{ render_waterfall_block(scope_bp_dc, bp_ocm_pct, bp_profit_pct, doc.vat_inclusive, doc.vat_percent | float, "#C89A2E") }}
    </div>

  </div>
{% endfor %}

{% else %}
{# Detailed (DPWH) mode — BP variant #}
{% for scope in scopes_detail %}
  {% set scope_num.value = scope_num.value + 1 %}

  {# Compute BP direct cost for this scope #}
  {% set scope_mat_rows_bp = frappe.db.sql("SELECT amount FROM `tabEstimate Scope Material` WHERE parent = %s", scope.name, as_dict=True) %}
  {% set scope_bp_mat_cost = namespace(value=0) %}
  {% for row in scope_mat_rows_bp %}{% set scope_bp_mat_cost.value = scope_bp_mat_cost.value + (row.amount | float) * bp_rate %}{% endfor %}
  {% set scope_bp_dc = (scope.total_labor_cost | float) + (scope.total_equipment_cost | float) + scope_bp_mat_cost.value %}

  <div style="page-break-before: always;">

    {{ cont_header() }}

    {% if scope.scope_group != current_group.value %}
      {% set current_group.value = scope.scope_group %}
      <div style="background-color: #1B2E4A; color: #ffffff; font-weight: bold; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; padding: 6px 10px; letter-spacing: 1px; font-size: 9.5pt; margin-bottom: 4mm;">
        {{ scope.scope_group | upper }}
      </div>
    {% endif %}

    <table style="width: 100%; background-color: #1B2E4A; color: #ffffff; margin-bottom: 4mm; border-collapse: collapse;">
      <tr>
        <td style="padding: 8px 10px; font-family: 'Montserrat', 'Segoe UI', Arial, sans-serif; font-size: 9pt; color: #ffffff; vertical-align: top;">
          <strong>SCOPE {{ scope_num.value }} of {{ scope_count }}</strong>: {{ scope.scope_name }}
          {% if scope.is_optional %}<span style="font-style: italic; color: #CCCCCC;"> (Optional)</span>{% endif %}
          {% if scope.dpwh_pay_item %}
          <div style="font-size: 8pt; color: #D0D7E0; margin-top: 2px;">Pay Item: {{ scope.dpwh_pay_item }}</div>
          {% endif %}
        </td>
        <td style="padding: 8px 10px; text-align: right; font-size: 8.5pt; color: #ffffff; vertical-align: top; white-space: nowrap;">
          {{ scope.scope_group }}
        </td>
      </tr>
      <tr>
        <td colspan="2" style="padding: 0 10px 6px 10px; font-size: 8pt; color: #E0E4E8;">
          {% set uom_display = scope.uom if scope.uom and scope.uom != "None" else "" %}
          {% if uom_display %}UOM: {{ uom_display }} &nbsp;|&nbsp; {% endif %}Qty: {{ num_format(scope.quantity) }}
          &nbsp;|&nbsp; Output/Day: {{ num_format(scope.output_per_day) }}
          &nbsp;|&nbsp; Duration: {{ num_format(scope.duration_days) }} days
        </td>
      </tr>
    </table>

    {% set labor_rows = frappe.db.sql("SELECT role, persons, daily_rate, total_rate, total_cost FROM `tabEstimate Scope Labor` WHERE parent = %s ORDER BY idx", scope.name, as_dict=True) %}
    {% if labor_rows %}
    <div class="section-header">A &mdash; LABOR</div>
    {{ render_labor_table(labor_rows, scope.duration_days | float) }}
    {% endif %}

    {% set equipment_rows = frappe.db.sql("SELECT e.item AS item_code, COALESCE(i.item_name, e.item) AS item_name, e.units, e.daily_rate, e.total_rate, e.total_cost FROM `tabEstimate Scope Equipment` e LEFT JOIN `tabItem` i ON i.name = e.item WHERE e.parent = %s ORDER BY e.idx", scope.name, as_dict=True) %}
    {% if equipment_rows %}
    <div class="section-header">B &mdash; EQUIPMENT &amp; PLANT</div>
    {{ render_equipment_table(equipment_rows, scope.duration_days | float) }}
    {% endif %}

    {% set material_rows = frappe.db.sql("SELECT m.item AS item_code, m.item_name, m.adjusted_qty, m.uom, m.buying_rate, m.amount, i.description AS item_description FROM `tabEstimate Scope Material` m LEFT JOIN `tabItem` i ON m.item = i.name WHERE m.parent = %s ORDER BY m.idx", scope.name, as_dict=True) %}
    {% if material_rows %}
    <div class="section-header">C &mdash; MATERIALS</div>
    {{ render_material_table(material_rows) }}
    {% if bp_rate != 1.0 %}
    <div style="font-size: 7.5pt; color: #777777; font-style: italic; text-align: right; margin-top: 2mm; margin-right: 4mm;">
      * Material amounts adjusted by BP factor {{ num_format(bp_rate) }}x in waterfall below.
    </div>
    {% endif %}
    {% endif %}

    <div style="margin-top: 8mm; page-break-inside: avoid;">
      {{ render_waterfall_block(scope_bp_dc, bp_ocm_pct, bp_profit_pct, doc.vat_inclusive, doc.vat_percent | float, "#C89A2E") }}
    </div>

  </div>
{% endfor %}
{% endif %}

{% endif %}{# end scope_count > 0 #}
